import{_ as o,o as t,c as s,ai as a}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"OpenResponses Gateway Plan","description":"","frontmatter":{"summary":"Plan: Add OpenResponses /v1/responses endpoint and deprecate chat completions cleanly","owner":"opensoul","status":"draft","last_updated":"2026-01-19","title":"OpenResponses Gateway Plan"},"headers":[],"relativePath":"experiments/plans/openresponses-gateway.md","filePath":"experiments/plans/openresponses-gateway.md","lastUpdated":1771906665000}'),n={name:"experiments/plans/openresponses-gateway.md"};function i(d,e,c,l,r,p){return t(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="openresponses-gateway-integration-plan" tabindex="-1"><a class="header-anchor" href="#openresponses-gateway-integration-plan">#</a> OpenResponses Gateway Integration Plan</h1><h2 id="context" tabindex="-1"><a class="header-anchor" href="#context">#</a> Context</h2><p>OpenSoul Gateway currently exposes a minimal OpenAI-compatible Chat Completions endpoint at <code>/v1/chat/completions</code> (see <a href="/docs/gateway/openai-http-api">OpenAI Chat Completions</a>).</p><p>Open Responses is an open inference standard based on the OpenAI Responses API. It is designed for agentic workflows and uses item-based inputs plus semantic streaming events. The OpenResponses spec defines <code>/v1/responses</code>, not <code>/v1/chat/completions</code>.</p><h2 id="goals" tabindex="-1"><a class="header-anchor" href="#goals">#</a> Goals</h2><ul><li>Add a <code>/v1/responses</code> endpoint that adheres to OpenResponses semantics.</li><li>Keep Chat Completions as a compatibility layer that is easy to disable and eventually remove.</li><li>Standardize validation and parsing with isolated, reusable schemas.</li></ul><h2 id="non-goals" tabindex="-1"><a class="header-anchor" href="#non-goals">#</a> Non-goals</h2><ul><li>Full OpenResponses feature parity in the first pass (images, files, hosted tools).</li><li>Replacing internal agent execution logic or tool orchestration.</li><li>Changing the existing <code>/v1/chat/completions</code> behavior during the first phase.</li></ul><h2 id="research-summary" tabindex="-1"><a class="header-anchor" href="#research-summary">#</a> Research Summary</h2><p>Sources: OpenResponses OpenAPI, OpenResponses specification site, and the Hugging Face blog post.</p><p>Key points extracted:</p><ul><li><code>POST /v1/responses</code> accepts <code>CreateResponseBody</code> fields like <code>model</code>, <code>input</code> (string or <code>ItemParam[]</code>), <code>instructions</code>, <code>tools</code>, <code>tool_choice</code>, <code>stream</code>, <code>max_output_tokens</code>, and <code>max_tool_calls</code>.</li><li><code>ItemParam</code> is a discriminated union of: <ul><li><code>message</code> items with roles <code>system</code>, <code>developer</code>, <code>user</code>, <code>assistant</code></li><li><code>function_call</code> and <code>function_call_output</code></li><li><code>reasoning</code></li><li><code>item_reference</code></li></ul></li><li>Successful responses return a <code>ResponseResource</code> with <code>object: &quot;response&quot;</code>, <code>status</code>, and <code>output</code> items.</li><li>Streaming uses semantic events such as: <ul><li><code>response.created</code>, <code>response.in_progress</code>, <code>response.completed</code>, <code>response.failed</code></li><li><code>response.output_item.added</code>, <code>response.output_item.done</code></li><li><code>response.content_part.added</code>, <code>response.content_part.done</code></li><li><code>response.output_text.delta</code>, <code>response.output_text.done</code></li></ul></li><li>The spec requires: <ul><li><code>Content-Type: text/event-stream</code></li><li><code>event:</code> must match the JSON <code>type</code> field</li><li>terminal event must be literal <code>[DONE]</code></li></ul></li><li>Reasoning items may expose <code>content</code>, <code>encrypted_content</code>, and <code>summary</code>.</li><li>HF examples include <code>OpenResponses-Version: latest</code> in requests (optional header).</li></ul><h2 id="proposed-architecture" tabindex="-1"><a class="header-anchor" href="#proposed-architecture">#</a> Proposed Architecture</h2><ul><li>Add <code>src/gateway/open-responses.schema.ts</code> containing Zod schemas only (no gateway imports).</li><li>Add <code>src/gateway/openresponses-http.ts</code> (or <code>open-responses-http.ts</code>) for <code>/v1/responses</code>.</li><li>Keep <code>src/gateway/openai-http.ts</code> intact as a legacy compatibility adapter.</li><li>Add config <code>gateway.http.endpoints.responses.enabled</code> (default <code>false</code>).</li><li>Keep <code>gateway.http.endpoints.chatCompletions.enabled</code> independent; allow both endpoints to be toggled separately.</li><li>Emit a startup warning when Chat Completions is enabled to signal legacy status.</li></ul><h2 id="deprecation-path-for-chat-completions" tabindex="-1"><a class="header-anchor" href="#deprecation-path-for-chat-completions">#</a> Deprecation Path for Chat Completions</h2><ul><li>Maintain strict module boundaries: no shared schema types between responses and chat completions.</li><li>Make Chat Completions opt-in by config so it can be disabled without code changes.</li><li>Update docs to label Chat Completions as legacy once <code>/v1/responses</code> is stable.</li><li>Optional future step: map Chat Completions requests to the Responses handler for a simpler removal path.</li></ul><h2 id="phase-1-support-subset" tabindex="-1"><a class="header-anchor" href="#phase-1-support-subset">#</a> Phase 1 Support Subset</h2><ul><li>Accept <code>input</code> as string or <code>ItemParam[]</code> with message roles and <code>function_call_output</code>.</li><li>Extract system and developer messages into <code>extraSystemPrompt</code>.</li><li>Use the most recent <code>user</code> or <code>function_call_output</code> as the current message for agent runs.</li><li>Reject unsupported content parts (image/file) with <code>invalid_request_error</code>.</li><li>Return a single assistant message with <code>output_text</code> content.</li><li>Return <code>usage</code> with zeroed values until token accounting is wired.</li></ul><h2 id="validation-strategy-no-sdk" tabindex="-1"><a class="header-anchor" href="#validation-strategy-no-sdk">#</a> Validation Strategy (No SDK)</h2><ul><li>Implement Zod schemas for the supported subset of: <ul><li><code>CreateResponseBody</code></li><li><code>ItemParam</code> + message content part unions</li><li><code>ResponseResource</code></li><li>Streaming event shapes used by the gateway</li></ul></li><li>Keep schemas in a single, isolated module to avoid drift and allow future codegen.</li></ul><h2 id="streaming-implementation-phase-1" tabindex="-1"><a class="header-anchor" href="#streaming-implementation-phase-1">#</a> Streaming Implementation (Phase 1)</h2><ul><li>SSE lines with both <code>event:</code> and <code>data:</code>.</li><li>Required sequence (minimum viable): <ul><li><code>response.created</code></li><li><code>response.output_item.added</code></li><li><code>response.content_part.added</code></li><li><code>response.output_text.delta</code> (repeat as needed)</li><li><code>response.output_text.done</code></li><li><code>response.content_part.done</code></li><li><code>response.completed</code></li><li><code>[DONE]</code></li></ul></li></ul><h2 id="tests-and-verification-plan" tabindex="-1"><a class="header-anchor" href="#tests-and-verification-plan">#</a> Tests and Verification Plan</h2><ul><li>Add e2e coverage for <code>/v1/responses</code>: <ul><li>Auth required</li><li>Non-stream response shape</li><li>Stream event ordering and <code>[DONE]</code></li><li>Session routing with headers and <code>user</code></li></ul></li><li>Keep <code>src/gateway/openai-http.e2e.test.ts</code> unchanged.</li><li>Manual: curl to <code>/v1/responses</code> with <code>stream: true</code> and verify event ordering and terminal <code>[DONE]</code>.</li></ul><h2 id="doc-updates-follow-up" tabindex="-1"><a class="header-anchor" href="#doc-updates-follow-up">#</a> Doc Updates (Follow-up)</h2><ul><li>Add a new docs page for <code>/v1/responses</code> usage and examples.</li><li>Update <code>/gateway/openai-http-api</code> with a legacy note and pointer to <code>/v1/responses</code>.</li></ul>',26)])])}const m=o(n,[["render",i]]);export{h as __pageData,m as default};
